CREATE TRIGGER [dbo].[BillOfProcess_History]ON [dbo].[BillOfProcess]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.BillOfProcessId IS NOT NULL AND d.BillOfProcessId IS NULL THEN 'I' 		WHEN i.BillOfProcessId IS NOT NULL AND d.BillOfProcessId IS NOT NULL THEN 'U' 		WHEN i.BillOfProcessId IS NULL AND d.BillOfProcessId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.BillOfProcessId = d.BillOfProcessId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_BillOfProcess([BillOfProcessId], [Name], [Description], [PartId], [EffectiveStartDate], [EffectiveStartDateUtc], [EffectiveEndDate], [EffectiveEndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfProcessId], [Name], [Description], [PartId], [EffectiveStartDate], [EffectiveStartDateUtc], [EffectiveEndDate], [EffectiveEndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_BillOfProcess([BillOfProcessId], [Name], [Description], [PartId], [EffectiveStartDate], [EffectiveStartDateUtc], [EffectiveEndDate], [EffectiveEndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfProcessId], [Name], [Description], [PartId], [EffectiveStartDate], [EffectiveStartDateUtc], [EffectiveEndDate], [EffectiveEndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND